const body = $json.body;

let subtotal = 0;

// Normalize items
const items = body.items.map(item => {
  const total = item.total_price_cents || (item.base_price_cents * item.qty);
  subtotal += total;

  return {
    ...item,
    total_price_cents: total
  };
});

// Tax
const TAX_RATE = 0.0952;
const tax = Math.round(subtotal * TAX_RATE);
const total = subtotal + tax;

// Order ID
const order_id =
  'UTO-' +
  $now.toFormat('x') +
  '-' +
  Math.random().toString(36).substr(2, 5).toUpperCase();

// ✅ Build Square item lines (NO tax)
const square_line_items = items.map(item => ({
  name: item.name,
  quantity: String(item.qty),
  base_price_money: {
    amount: Math.round(item.total_price_cents / item.qty),
    currency: 'USD'
  }
}));

// ✅ Inject tax as line item
const tax_line_item = {
  name: "Sales Tax (9.52%)",
  quantity: "1",
  base_price_money: {
    amount: tax,
    currency: "USD"
  }
};

// ✅ Final line items WITH tax
const square_line_items_with_tax = [
  ...square_line_items,
  tax_line_item
];

// ✅ RETURN ONLY WHAT THE HTTP NODE NEEDS
return {
  json: {
    ...$json,

    cart_id: order_id,
    square_line_items_with_tax,
    subtotal_cents: subtotal,
    tax_cents: tax,

    body: {
      ...body,
      items,
      subtotal_cents: subtotal,
      tax_cents: tax,
      frontend_total_cents: total,
      order_id
    }
  }
};

const computeTotals = $("Compute Totals").first().json;
const squareResponse = $input.first().json;

return {
  json: {
    ...computeTotals,
    payment_link: squareResponse.payment_link,
    order_id: squareResponse.order_id,
    related_resources: squareResponse.related_resources
  }
};

const sqlite3 = require('sqlite3').verbose();

const dbPath = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';

const merged = $('Merge').first().json;
const body = merged.body || {};

const paymentLink = merged.payment_link || {};
const linkUrl =
  paymentLink.url ||
  paymentLink.long_url ||
  '';

const customer = body.customer || {};
const items = Array.isArray(body.items) ? body.items : [];

const orderId = String(body.order_id || merged.order_id || '').trim();

const subtotalCents = Number(body.subtotal_cents || 0) || 0;
const taxCents = Number(body.tax_cents || 0) || 0;
const totalCents = Number(
  body.frontend_total_cents ??
  body.total_cents ??
  0
) || 0;

return new Promise((resolve) => {
  const db = new sqlite3.Database(dbPath, (err) => {
    if (err) {
      resolve([
        {
          json: {
            db_saved: false,
            db_error: err.message,
            order_id: orderId
          }
        }
      ]);
      return;
    }

    db.run(
      `
      INSERT INTO orders (
        order_id,
        customer_name,
        customer_email,
        customer_phone,
        customer_city,
        customer_county,
        cart_json,
        subtotal_cents,
        tax_cents,
        total_cents,
        square_payment_link,
        square_order_id,
        notes,
        status,
        source,
        email_sent
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `,
      [
        orderId,
        customer.name || '',
        customer.email || '',
        customer.phone || '',
        customer.city || 'Little Rock',
        customer.county || '',
        JSON.stringify(items),
        subtotalCents,
        taxCents,
        totalCents,
        linkUrl,
        merged.square_order_id || merged.order_id || '',
        body.notes || customer.notes || '',
        'pending',
        'pickup-order',
        0
      ],
      function(err) {
        if (err) {
          resolve([
            {
              json: {
                db_saved: false,
                db_error: err.message,
                order_id: orderId
              }
            }
          ]);
        } else {
          resolve([
            {
              json: {
                db_saved: true,
                db_rowid: this.lastID,
                order_id: orderId,
                source: 'pickup-order'
              }
            }
          ]);
        }

        db.close();
      }
    );
  });
});

const merged = $("Merge").first().json;
const dbResult = $("Save to SQLite").first().json;
const paymentLink = merged.payment_link || {};
const squareLink = (paymentLink.url || paymentLink.long_url) || '';

return { json: { ok: true, message: 'Order received! Check your email for payment link.', square_link: squareLink, order_id: merged.body.order_id || '', total_cents: merged.body.frontend_total_cents || 0, db_saved: dbResult.db_saved || false } };

