const link = $json.payment_link?.url;
if (!link) throw new Error('No payment link');

return [{json:{
  ...$input.first().json,
  payment_link: link,
  status:'payment_required'
}}];

const body = $json.body || $json;

if (body.source !== 'meal-prep') {
  throw new Error('Invalid source');
}

const required = ['customer','items','pricing'];
const missing = required.filter(k => !body[k]);
if (missing.length) {
  throw new Error('Missing fields: ' + missing.join(','));
}

const cust = body.customer;
if (!cust.name || !cust.phone || !cust.email) {
  throw new Error('Missing customer info');
}

const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRe.test(cust.email)) throw new Error('Invalid email');

const phoneDigits = String(cust.phone).replace(/\D/g,'');
if (phoneDigits.length < 10) throw new Error('Invalid phone');

const items = body.items;
if (!Array.isArray(items) || !items.length) {
  throw new Error('No meal items');
}

const pricing = body.pricing;
const expected = (pricing.subtotal||0)+(pricing.labor||0)+(pricing.tax||0);
if (Math.abs(expected - pricing.total) > 2) {
  throw new Error('Pricing mismatch');
}

const now = new Date();
const cst = new Date(now.toLocaleString('en-US',{timeZone:'America/Chicago'}));
const day = cst.getDay();

// Keep pickup logic (Thursday schedule still enforced)
const pickupDate = new Date(cst);
const daysUntilThu = (4 - day + 7) % 7 || 7;
pickupDate.setDate(pickupDate.getDate() + daysUntilThu);

const ymd = cst.toISOString().slice(0,10).replace(/-/g,'');
const seq = String(Math.floor(Math.random()*900)+100);
const order_id = `UMP-${ymd}-${seq}`;

return [{json:{
  ...body,
  order_id,
  phone_digits: phoneDigits,
  pickup_date: pickupDate.toISOString().split('T')[0]
}}];

const input = $json;
const items = input.items || [];

// Build Square line items (NO tax)
const square_line_items = items.map(item => ({
  name: item.name,
  quantity: String(item.qty),
  base_price_money: {
    amount: item.price,
    currency: 'USD'
  }
}));

// Add labor fee as line item
square_line_items.push({
  name: 'Labor & Packaging',
  quantity: '1',
  base_price_money: {
    amount: input.pricing.labor,
    currency: 'USD'
  }
});

// Add tax as line item (matches your v4 checkout pattern)
const tax_line_item = {
  name: 'Tax (9.52%)',
  quantity: '1',
  base_price_money: {
    amount: input.pricing.tax,
    currency: 'USD'
  }
};

// Final line items WITH tax
const square_line_items_with_tax = [
  ...square_line_items,
  tax_line_item
];

// Generate order ID (matching v4 pattern)
const ymd = $now.toFormat('yyyyMMdd');
const seq = Math.random().toString(36).substr(2, 3).toUpperCase();
const order_id = 'UMP-' + ymd + '-' + seq;

// RETURN ONLY WHAT THE HTTP NODE NEEDS
return [{
  json: {
    ...input,
    order_id,
    cart_id: order_id,
    square_line_items_with_tax,
    square_total: input.pricing.total,
    subtotal_cents: input.pricing.subtotal,
    labor_cents: input.pricing.labor,
    tax_cents: input.pricing.tax
  }
}];

const computeTotals = $("mp compute totals").first().json;
const squareResponse = $input.first().json;

return {
  json: {
    ...computeTotals,
    payment_link: squareResponse.payment_link,
    order_id: squareResponse.order_id,
    related_resources: squareResponse.related_resources
  }
};

